
Component({
  properties: {
    // 样式
    type: {
      type: Number,
      value: 1
    },
    text: {
      type: String,
      value: ''
    },
    bgColor: {
      type: String,
      value: '#fff'
    },
    textColor: {
      type: String,
      value: '#000'
    },
    href: {
      type: Object,
      value: null
    },
    mobile: {
      type: String,
      value: ''
    }
  },
  methods: {
    clickButton() {
      if (this.data.mobile) {
        wx.makePhoneCall({
          phoneNumber: this.data.mobile
        })
        return
      }
      if (!this.data.href) {
        return
      }
      this.triggerEvent('dealPath', {
        data: this.data.href
      })
    }
  }
})
